  5	import {
  6	  Button,
  7	  MenuToggle,
  8	  MenuToggleProps,
  9	  MenuToggleElement,
 10	  Select,
 11	  SelectProps,
 12	  SelectList,
 13	  SelectOption,
 14	  SelectOptionProps,
 15	  TextInputGroup,
 16	  TextInputGroupMain,
 17	  TextInputGroupUtilities,
 18	} from '@patternfly/react-core';
 19	import * as _ from 'lodash-es';
 20	import * as React from 'react';
 21	import { useTranslation } from 'react-i18next';
 22	import { TimesIcon } from '@patternfly/react-icons/dist/esm/icons/times-icon';
