 24	export type SingleTypeaheadDropdownProps = {
 25	  /** The items to display in the dropdown */
 26	  items: (SelectOptionProps & {
 27	    children?: string;
 28	  })[];
 29	  /** The function to call when the selected item changes */
 30	  onChange: (v: string) => void;
 31	  /** The function to call when the selected item is cleared */
 32	  onClear?: (v: string) => void;
 33	  /** The function to call when an item is created */
 34	  onCreate?: (v: string) => void;
 35	  /** The function to call when the input value changes */
 36	  onInputChange?: (v: string) => void;
 37	  /** The key of the selected item */
 38	  selectedKey: string;
 39	  /** The placeholder text to display in the input */
 40	  placeholder?: string;
 41	  /** Whether to hide the clear button */
 42	  hideClearButton?: boolean;
 43	  /** Whether to resize the dropdown to fit the selected item */
 44	  resizeToFit?: boolean;
 45	  /** Whether to enable creating new items */
 46	  enableCreateNew?: boolean;
 47	  /** The component to use render the dropdown options */
 48	  OptionComponent?: React.FC<SelectOptionProps>;
 49	
 50	  /** Additional props to pass to MenuToggle */
 51	  menuToggleProps?: Partial<MenuToggleProps>;
 52	  /** Additional props to pass to Select */
 53	  selectProps?: Partial<SelectProps>;
 54	  /** Clear the current items in the dropdown when new items are added */
 55	  clearOnNewItems?: boolean;
 56	};
