 58	/**
 59	 * Uses canvas.measureText to compute and return the width of the given text
 60	 * of given font in pixels.
 61	 *
 62	 * @param text - The text to be rendered.
 63	 * @param font - The css font descriptor that text is to be rendered with
 64	 * (e.g. "bold 14px verdana").
 65	 *
 66	 * @see https://stackoverflow.com/questions/118241/calculate-text-width-with-javascript/21015393#21015393
 67	 */
 68	const getTextWidth = (text: string, font: string): number => {
 69	  // re-use canvas object for better performance
 70	  const canvas: HTMLCanvasElement =
 71	    // eslint-disable-next-line @typescript-eslint/ban-ts-comment
 72	    // @ts-ignore
 73	    getTextWidth.canvas || (getTextWidth.canvas = document.createElement('canvas'));
 74	  const context = canvas.getContext('2d');
 75	  context.font = font;
 76	  const metrics = context.measureText(text);
 77	  return Math.ceil(metrics.width);
 78	};
