 82	  items,
 83	  onChange,
 84	  onClear,
 85	  onCreate,
 86	  onInputChange,
 87	  selectedKey,
 88	  placeholder,
 89	  hideClearButton = false,
 90	  resizeToFit = false,
 91	  enableCreateNew = false,
 92	  OptionComponent,
 93	  menuToggleProps = {},
 94	  selectProps = {},
 95	  clearOnNewItems = false,
 96	}) => {
 97	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 98	  const [isOpen, setIsOpen] = React.useState(false);
 99	  const [selectOptions, setSelectOptions] = React.useState<
100	    (SelectOptionProps & {
101	      children?: string;
102	    })[]
103	  >(items);
104	  const selectedValue = React.useMemo(
105	    () => selectOptions.find((i) => i.value === selectedKey),
106	    [selectOptions, selectedKey],
107	  );
108	  const [inputValue, setInputValue] = React.useState<string>(selectedValue?.children || '');
109	  const [filterValue, setFilterValue] = React.useState<string>('');
110	  const [filteredSelectOptions, setFilteredSelectOptions] =
111	    React.useState<SelectOptionProps[]>(items);
112	  const [focusedItemIndex, setFocusedItemIndex] = React.useState<number | null>(null);
113	  const [activeItemId, setActiveItemId] = React.useState<string | null>(null);
114	  const textInputRef = React.useRef<HTMLInputElement>();
115	
116	  const ID_PREFIX = _.uniqueId('select-typeahead-'); // for aria to work, ids have to be unique
117	  const NO_RESULTS = 'typeahead-dropdown__no-results';
118	  const CREATE_NEW = 'typeahead-dropdown__create-new';
119	
120	  React.useEffect(() => {
121	    let newSelectOptions = [];
122	    if (clearOnNewItems) {
123	      newSelectOptions = [...items];
124	    } else {
125	      newSelectOptions = [..._.differenceBy(items, selectOptions, 'value'), ...selectOptions];
126	    }
127	    setSelectOptions(newSelectOptions);
128	    // eslint-disable-next-line react-hooks/exhaustive-deps
129	  }, [items]);
130	
131	  React.useEffect(() => {
132	    setFilteredSelectOptions(selectOptions);
133	  }, [selectOptions]);
134	
135	  React.useEffect(() => {
136	    let newSelectOptions: SelectOptionProps[] = selectOptions;
137	
138	    // Filter menu items based on the text input value when one exists
139	    if (filterValue) {
140	      newSelectOptions = selectOptions.filter((menuItem) =>
141	        String(menuItem.children).toLowerCase().includes(filterValue.toLowerCase()),
142	      );
143	
144	      // If no option matches the filter exactly, display creation option
145	      if (enableCreateNew && !selectOptions.some((option) => option.value === inputValue)) {
146	        newSelectOptions = [
147	          ...newSelectOptions,
148	          {
149	            children: t('Create new option "{{option}}"', { option: inputValue }),
150	            value: CREATE_NEW,
151	          },
152	        ];
153	      }
154	
155	      // Open the menu when the input value changes and the new value is not empty
156	      if (!isOpen) {
157	        setIsOpen(true);
158	      }
159	    }
160	
161	    setFilteredSelectOptions(newSelectOptions);
162	    // eslint-disable-next-line react-hooks/exhaustive-deps
163	  }, [filterValue]);
164	
165	  const createItemId = (value: any) => `${ID_PREFIX}-option-${String(value).replace(' ', '-')}`;
166	
167	  const setActiveAndFocusedItem = (itemIndex: number) => {
168	    setFocusedItemIndex(itemIndex);
169	    const focusedItem = filteredSelectOptions[itemIndex];
170	    setActiveItemId(createItemId(focusedItem.value));
171	  };
172	
173	  const resetActiveAndFocusedItem = () => {
174	    setFocusedItemIndex(null);
175	    setActiveItemId(null);
176	  };
177	
178	  const closeMenu = () => {
179	    setIsOpen(false);
180	    resetActiveAndFocusedItem();
181	  };
182	
183	  const onInputClick = () => {
184	    if (!isOpen) {
185	      setIsOpen(true);
186	    } else if (!inputValue) {
187	      closeMenu();
188	    }
189	  };
190	
191	  const selectOption = (value: string | number, content: string | number) => {
192	    setInputValue(String(content));
193	    setFilterValue('');
194	    onChange(String(value));
195	
196	    closeMenu();
197	  };
198	
199	  const onSelect = (
200	    _event: React.MouseEvent<Element, MouseEvent> | undefined,
201	    value: SelectOptionProps['value'] | undefined,
202	  ) => {
203	    if (enableCreateNew && value === CREATE_NEW) {
204	      if (!selectOptions.some((item) => item.value === filterValue)) {
205	        setSelectOptions([...selectOptions, { value: filterValue, children: filterValue }]);
206	        onCreate && onCreate(filterValue);
207	      }
208	      selectOption(filterValue, filterValue);
209	      resetActiveAndFocusedItem();
210	    } else if (value && value !== NO_RESULTS) {
211	      const selectedOption = selectOptions.find((i) => i.value === value);
212	      selectOption(value, selectedOption?.children ?? selectedOption?.value ?? '');
213	    }
214	  };
215	
216	  React.useEffect(() => {
217	    setInputValue(selectedValue?.children ?? selectedValue?.value ?? '');
218	  }, [selectedValue]);
219	
220	  const onTextInputChange = (_event: React.FormEvent<HTMLInputElement>, value: string) => {
221	    setInputValue(value);
222	    setFilterValue(value);
223	    onInputChange && onInputChange(value);
224	
225	    resetActiveAndFocusedItem();
226	  };
227	
228	  const handleMenuArrowKeys = (key: string) => {
229	    let indexToFocus = 0;
230	
231	    if (!isOpen) {
232	      setIsOpen(true);
233	    }
234	
235	    if (filteredSelectOptions.every((option) => option.isDisabled)) {
236	      return;
237	    }
238	
239	    if (key === 'ArrowUp') {
240	      if (focusedItemIndex === null || focusedItemIndex === 0) {
241	        indexToFocus = filteredSelectOptions.length - 1;
242	      } else {
243	        indexToFocus = focusedItemIndex - 1;
244	      }
245	
246	      // Skip disabled options
247	      while (filteredSelectOptions[indexToFocus].isDisabled) {
248	        indexToFocus--;
249	        if (indexToFocus === -1) {
250	          indexToFocus = filteredSelectOptions.length - 1;
251	        }
252	      }
253	    }
254	
255	    if (key === 'ArrowDown') {
256	      if (focusedItemIndex === null || focusedItemIndex === filteredSelectOptions.length - 1) {
257	        indexToFocus = 0;
258	      } else {
259	        indexToFocus = focusedItemIndex + 1;
260	      }
261	
262	      // Skip disabled options
263	      while (filteredSelectOptions[indexToFocus].isDisabled) {
264	        indexToFocus++;
265	        if (indexToFocus === filteredSelectOptions.length) {
266	          indexToFocus = 0;
267	        }
268	      }
269	    }
270	
271	    setActiveAndFocusedItem(indexToFocus);
272	  };
273	
274	  const onInputKeyDown = (event: React.KeyboardEvent<HTMLInputElement>) => {
275	    const focusedItem = focusedItemIndex !== null ? filteredSelectOptions[focusedItemIndex] : null;
276	
277	    switch (event.key) {
278	      case 'Enter':
279	        if (
280	          isOpen &&
281	          focusedItem &&
282	          focusedItem.value !== NO_RESULTS &&
283	          !focusedItem.isAriaDisabled
284	        ) {
285	          onSelect(null, focusedItem.value);
286	        }
287	
288	        if (!isOpen) {
289	          setIsOpen(true);
290	        }
291	
292	        break;
293	      case 'ArrowUp':
294	      case 'ArrowDown':
295	        event.preventDefault();
296	        handleMenuArrowKeys(event.key);
297	        break;
298	      default:
299	        break;
300	    }
301	  };
302	
303	  const onToggleClick = () => {
304	    setIsOpen(!isOpen);
305	    textInputRef?.current?.focus();
306	  };
307	
308	  const onClearButtonClick = () => {
309	    onChange('');
310	    setInputValue('');
311	    setFilterValue('');
312	    resetActiveAndFocusedItem();
313	    textInputRef?.current?.focus();
314	    onClear && onClear(selectedKey);
315	  };
316	
317	  const selectedItemWidth = React.useMemo(() => {
318	    // font is hardcoded because canvas can't read the non-global CSS variables
319	    return (
320	      resizeToFit &&
321	      selectedValue &&
322	      getTextWidth(String(selectedValue.children), '14px RedHatText')
323	    );
324	  }, [resizeToFit, selectedValue]);
325	
326	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
327	    <MenuToggle
328	      ref={toggleRef}
329	      variant="typeahead"
330	      onClick={onToggleClick}
331	      isExpanded={isOpen}
332	      {...menuToggleProps}
333	    >
334	      <TextInputGroup isPlain>
335	        <TextInputGroupMain
336	          value={inputValue}
337	          onClick={onInputClick}
338	          onChange={onTextInputChange}
339	          onKeyDown={(ev: React.KeyboardEvent<HTMLInputElement>) => {
340	            ev.key === 'Enter' && ev.preventDefault(); // prevent accidental form submission
341	            onInputKeyDown(ev);
342	          }}
343	          id={`${ID_PREFIX}-input`}
344	          autoComplete="off"
345	          innerRef={textInputRef}
346	          placeholder={placeholder ?? t('Filter options')}
347	          {...(activeItemId && { 'aria-activedescendant': activeItemId })}
348	          role="combobox"
349	          isExpanded={isOpen}
350	          aria-controls={`${ID_PREFIX}-listbox`}
351	          style={
352	            // need to use max to account for min-width of the input element in PF
353	            resizeToFit
354	              ? {
355	                  // eslint-disable-next-line max-len
356	                  width: `max(calc(${selectedItemWidth}px + var(--pf-v6-c-text-input-group__text-input--PaddingLeft) + var(--pf-v6-c-text-input-group__text-input--PaddingRight)), var(--pf-v6-c-text-input-group__text-input--MinWidth))`,
357	                }
358	              : {}
359	          }
360	        />
361	        {!hideClearButton && (
362	          <TextInputGroupUtilities {...(!inputValue ? { style: { display: 'none' } } : {})}>
363	            <Button
364	              variant="plain"
365	              onClick={onClearButtonClick}
366	              aria-label={t('Clear input value')}
367	              icon={<TimesIcon aria-hidden />}
368	            />
369	          </TextInputGroupUtilities>
370	        )}
371	      </TextInputGroup>
372	    </MenuToggle>
373	  );
374	
375	  return (
376	    <Select
377	      id={ID_PREFIX}
378	      isOpen={isOpen}
379	      selected={selectedKey}
380	      onSelect={onSelect}
381	      onOpenChange={(open) => {
382	        open ? setIsOpen(true) : closeMenu();
383	      }}
384	      toggle={toggle}
385	      shouldFocusFirstItemOnOpen={false}
386	      {...selectProps}
387	    >
388	      <SelectList id={`${ID_PREFIX}-listbox`}>
389	        {filteredSelectOptions.map((v, k) => {
390	          const SelectOptionComponent =
391	            v.value === CREATE_NEW ? SelectOption : OptionComponent ?? SelectOption;
392	
393	          return (
394	            <SelectOptionComponent
395	              key={k}
396	              isSelected={selectedKey === v.value}
397	              isFocused={focusedItemIndex === k}
398	              id={createItemId(k)}
399	              value={v.value}
400	              {...v}
401	            >
402	              {v.children || v.value}
403	            </SelectOptionComponent>
404	          );
405	        })}
406	        {_.isEmpty(filteredSelectOptions) && filterValue && !enableCreateNew && (
407	          <SelectOption isDisabled={true} isAriaDisabled={true} value={NO_RESULTS}>
408	            {t(`No results found`)}
409	          </SelectOption>
410	        )}
411	      </SelectList>
412	    </Select>
413	  );
414	};
